const MAX_URL_LENGTH = 2048;
const MAX_PARAM_LENGTH = 500;

const sanitizeString = (str) => {
  if (!str || typeof str !== 'string') return '';
  return str.replace(/[<>'"]/g, '').substring(0, MAX_PARAM_LENGTH);
};

const validateUrl = (url) => {
  if (!url || typeof url !== 'string') {
    return { valid: false, error: 'Invalid URL format' };
  }

  if (url.length > MAX_URL_LENGTH) {
    return { valid: false, error: 'URL too long' };
  }

  try {
    const urlObj = new URL(url);
    
    if (!ALLOWED_SCHEMES.includes(urlObj.protocol.replace(':', ''))) {
      return { valid: false, error: 'Invalid URL scheme' };
    }

    const host = urlObj.hostname || urlObj.pathname.split('/')[0];
    if (!ALLOWED_HOSTS.includes(host)) {
      return { valid: false, error: 'Invalid host' };
    }

    return { valid: true, urlObj, host };
  } catch (error) {
    return { valid: false, error: 'Malformed URL' };
  }
};

const parseDeepLink = (url) => {
  const validation = validateUrl(url);
  
  if (!validation.valid) {
    console.warn('Deep link validation failed:', validation.error);
    return null;
  }

  const { urlObj, host } = validation;
  const pathname = urlObj.pathname || urlObj.href.split(host)[1] || '';
  
  const routeConfig = ROUTE_PATTERNS[host];
  if (!routeConfig) {
    console.warn('No route configuration found for host:', host);
    return null;
  }

  const matches = pathname.match(routeConfig.pattern);
  if (!matches) {
    console.warn('Path does not match pattern for host:', host);
    return null;
  }

  const params = routeConfig.params(matches);
  
  const sanitizedParams = {};
  for (const [key, value] of Object.entries(params)) {
    if (typeof value === 'string') {
      sanitizedParams[key] = sanitizeString(value);
    } else if (typeof value === 'number' || typeof value === 'boolean') {
      sanitizedParams[key] = value;
    } else {
      sanitizedParams[key] = String(value);
    }
  }

  const queryParams = {};
  urlObj.searchParams.forEach((value, key) => {
    const sanitizedKey = sanitizeString(key);
    const sanitizedValue = sanitizeString(value);
    if (sanitizedKey && sanitizedValue) {
      queryParams[sanitizedKey] = sanitizedValue;
    }
  });

  return {
    screen: routeConfig.screen,
    params: { ...sanitizedParams, ...queryParams }
  };
};

